const payload = $input.item.json.body || $input.item.json;
const commits = payload.commits || [];
const repoName = payload.repository ? payload.repository.full_name : 'vanguard';
const branch = payload.ref ? payload.ref.replace('refs/heads/', '') : 'main';
const ultimoCommit = commits[commits.length - 1];
const mensagem = ultimoCommit ? ultimoCommit.message : 'sem mensagem';
const sha = ultimoCommit ? ultimoCommit.id.substring(0, 7) : '0000000';
const temResolve = mensagem.includes('[RESOLVE:');
const resolveMatch = mensagem.match(/\[RESOLVE:\s*([^\]]+)\]/);
const pendente = resolveMatch ? resolveMatch[1].trim() : '';
const linhas = ['[COMMIT] ' + repoName, sha + ' | ' + branch, mensagem];
if (temResolve) linhas.push('RESOLVE: ' + pendente);
const texto = linhas.join('\n');
return [{ json: { repoName: repoName, branch: branch, sha: sha, mensagem: mensagem, temResolve: temResolve, pendente: pendente, texto: texto } }];

const item = $('Extrair Dados do Push').item.json;
const tsStr = new Date().toISOString().replace('T',' ').slice(0,16) + ' UTC';
const blocos = [{
  object:'block',type:'heading_3',
  heading_3:{rich_text:[{type:'text',text:{content:'Commit '+tsStr}}]}
}];
const linhas = [
  'SHA: '+(item.sha||'').slice(0,7)+' | Branch: '+(item.branch||''),
  'Msg: '+(item.mensagem||'').split('
')[0].slice(0,200)
];
if(item.temResolve) linhas.push('RESOLVE: '+item.pendente);
linhas.forEach(function(l){
  blocos.push({object:'block',type:'bulleted_list_item',
    bulleted_list_item:{rich_text:[{type:'text',text:{content:l}}]}});
});
return [{ json: { notionChildren: blocos } }];

